    string lastSubstring(string s) {
        int n = s.size(), max_idx = 0;
        for (int i = 1; i < n; ++i) {
            if (s[i] > s[max_idx]) max_idx = i;
            else if (s[i] == s[max_idx]) {
                int j = 1;
                while (i + j < n && max_idx + j < n && s[i + j] == s[max_idx + j]) ++j;
                if (i + j < n && s[i + j] > s[max_idx + j]) max_idx = i;
            }
        }
        return s.substr(max_idx);
    }
};
